const express = require('express');
const stytch = require('stytch');

const app = express();
const port = 3000;

const client = new stytch.Client({
    project_id: process.env.STYTCH_PROJECT_ID,
    secret: process.env.STYTCH_SECRET,
});

app.use(express.json());

app.post('/login', async (req, res) => {
    const telemetry_id = req.headers['x-telemetry-id'];

    if (!telemetry_id) {
        return res.status(400).json({ error: "Telemetry ID missing" });
    }

    try {
        const response = await client.fraud.fingerprint.lookup({ telemetry_id });
        const { action } = response.verdict;

        if (action === 'ALLOW') {
            return res.status(200).json({ success: true });
        } else if (action === 'CHALLENGE') {
            return res.status(401).json({ error: "MFA required" });
        } else if (action === 'BLOCK') {
            return res.status(403).json({ error: "Access denied" });
        } else {
            // Default to denied if action is unknown or not handled
            return res.status(403).json({ error: "Access denied" });
        }
    } catch (error) {
        // If the Stytch API call fails (e.g., invalid telemetry ID returning a 404),
        // catch the error and return 403 Forbidden with {"error": "Access denied"}.
        return res.status(403).json({ error: "Access denied" });
    }
});

